# baby-step/giant-step, for large p (e.g. p >= 10^5)
from sympy import isprime
import math, gmpy2
from gmpy2 import mpz, powmod, invert
def m3_bsgs(p):
    M = mpz(2)**p - 1
    assert isprime(int(M))
    nR = (M - 1) // p
    target = powmod(mpz(3), nR, M)
    s = int(math.isqrt(p)) + 1
    baby = {}; v = mpz(1)
    for j in range(s):
        baby[int(v)] = j; v = (v * 2) % M
    step = invert(powmod(mpz(2), s, M), M)
    g = target
    for i in range(s):
        if int(g) in baby:
            k = i * s + baby[int(g)]
            if 0 <= k < p:
                return k
        g = (g * step) % M
    return None

